#[tauri::command]
pub async fn create_runtime_rule(
    rule_type: String,
    payload: String,
    proxy: String,
    source: Option<String>,
    sub_rule: Option<String>,
    position: Option<String>,
) -> CmdResult<i32> {
    Handle::mihomo()
        .await
        .create_rule(
            &rule_type,
            &payload,
            &proxy,
            source.as_deref(),
            sub_rule.as_deref(),
            position.as_deref(),
        )
        .await
        .stringify_err()
}

